import { useState } from "react";
import Card from "../components/ui/Card";
import Input from "../components/ui/Input";
import select from "../components/ui/select";
import btn from "../components/ui/btn";
import Icon from "../components/ui/Icon";
import { ADMIN_CREDENTIALS } from "../Data/InitialData";
import { genId, today } from "../Utils/Helper";

const AuthPage = ({ onLogin, students, onRegister }) => {
  const [mode, setMode] = useState("login");
  const [role, setRole] = useState("student");
  const [form, setForm] = useState({ name: "", email: "", password: "", phone: "", course: "", year: "" });
  const [error, setError] = useState("");

  const handle = (k, v) => setForm(f => ({ ...f, [k]: v }));

  const submit = () => {
    setError("");
    if (mode === "login") {
      if (role === "admin") {
        if (form.email === ADMIN_CREDENTIALS.email && form.password === ADMIN_CREDENTIALS.password)
          return onLogin({ role: "admin", name: "Administrator", email: form.email });
        return setError("Invalid admin credentials.");
      }
      const student = students.find(s => s.email === form.email && s.password === form.password);
      if (!student) return setError("Invalid email or password.");
      onLogin({ ...student, role: "student" });
    } else {
      if (!form.name || !form.email || !form.password || !form.phone || !form.course || !form.year)
        return setError("All fields are required.");
      if (students.find(s => s.email === form.email)) return setError("Email already registered.");
      const newStudent = { id: genId(), ...form, role: "student", registeredOn: today(), roomId: null };
      onRegister(newStudent);
      onLogin({ ...newStudent, role: "student" });
    }
  };

  return (
    <div style={{ minHeight: "100vh", background: "linear-gradient(135deg,#0f172a 0%,#1e3a5f 50%,#0f172a 100%)", display: "flex", alignItems: "center", justifyContent: "center", padding: 24 }}>
      <div style={{ width: "100%", maxWidth: 440 }}>
        <div style={{ textAlign: "center", marginBottom: 32 }}>
          <div style={{ display: "inline-flex", alignItems: "center", gap: 12, color: "#fff" }}>
            <div style={{ width: 48, height: 48, background: "linear-gradient(135deg,#3b82f6,#6366f1)", borderRadius: 14, display: "flex", alignItems: "center", justifyContent: "center" }}>
              <Icon name="building" size={26} />
            </div>
            <div>
              <div style={{ fontSize: 22, fontWeight: 900 }}>HostelHub</div>
              <div style={{ fontSize: 12, color: "#94a3b8" }}>Allotment Management System</div>
            </div>
          </div>
        </div>

        <Card>
          <div style={{ display: "flex", background: "#f1f5f9", borderRadius: 10, padding: 4, marginBottom: 24 }}>
            {["login", "register"].map(m => (
              <button key={m} onClick={() => { setMode(m); setError(""); }} style={{
                flex: 1, padding: "8px 0", border: "none", borderRadius: 8, fontWeight: 700,
                fontSize: 13, cursor: "pointer", fontFamily: "inherit",
                background: mode === m ? "#fff" : "transparent",
                color: mode === m ? "#1e293b" : "#64748b",
              }}>{m === "login" ? "Sign In" : "Register"}</button>
            ))}
          </div>

          {mode === "login" && (
            <div style={{ display: "flex", gap: 10, marginBottom: 20 }}>
              {["student", "admin"].map(r => (
                <button key={r} onClick={() => setRole(r)} style={{
                  flex: 1, padding: "10px 0", borderRadius: 10, cursor: "pointer", fontFamily: "inherit",
                  fontWeight: 700, fontSize: 13,
                  background: role === r ? (r === "admin" ? "#1e293b" : "#eff6ff") : "#f8fafc",
                  color: role === r ? (r === "admin" ? "#fff" : "#2563eb") : "#94a3b8",
                  border: role === r ? "none" : "1.5px solid #e2e8f0",
                }}>
                  <Icon name={r === "admin" ? "shield" : "users"} size={14} /> {r === "admin" ? "Admin" : "Student"}
                </button>
              ))}
            </div>
          )}

          {error && (
            <div style={{ background: "#fee2e2", color: "#b91c1c", borderRadius: 8, padding: "10px 14px", fontSize: 13, marginBottom: 16 }}>
              {error}
            </div>
          )}

          <Input label="Email" type="email" placeholder="you@example.com" value={form.email} onChange={e => handle("email", e.target.value)} />
          <Input label="Password" type="password" placeholder="••••••••" value={form.password} onChange={e => handle("password", e.target.value)} />

          {mode === "register" && (
            <>
              <Input label="Full Name" placeholder="Your full name" value={form.name} onChange={e => handle("name", e.target.value)} />
              <Input label="Phone Number" type="tel" placeholder="+91 XXXXXXXXXX" value={form.phone} onChange={e => handle("phone", e.target.value)} />
              <Input label="Course" placeholder="B.Tech CSE" value={form.course} onChange={e => handle("course", e.target.value)} />
              <select label="Year" value={form.year} onChange={e => handle("year", e.target.value)} style={{
                width: "100%", boxSizing: "border-box", padding: "10px 14px", border: "1.5px solid #e2e8f0",
                borderRadius: 10, fontSize: 14, outline: "none", background: "#f8fafc", fontFamily: "inherit",
                marginBottom: 16
              }}>
                <option value="">Select Year</option>
                {["1st Year", "2nd Year", "3rd Year", "4th Year"].map(y => <option key={y} value={y}>{y}</option>)}
              </select>
            </>
          )}

          <btn onClick={submit} style={{ width: "100%", justifyContent: "center" }}>
            {mode === "login" ? "Sign In" : "Create Account"}
          </btn>

          {mode === "login" && (
            <div style={{ marginTop: 16, padding: "12px 14px", background: "#f8fafc", borderRadius: 10, fontSize: 12, color: "#64748b" }}>
              <strong>Admin demo:</strong> admin@hostel.edu / admin123
            </div>
          )}
        </Card>
      </div>
    </div>
  );
};

export default AuthPage;
